"use strict";exports.id=9029,exports.ids=[9029],exports.modules={69029:(e,t,i)=>{i.r(t),i.d(t,{gitResourceData:()=>r});let r={sections:[{id:"official-docs",title:"Official Documentation",description:"Primary references maintained by standard bodies and the Git core team.",icon:"BookOpen",resources:[{title:"Git Official Reference Documentation",url:"https://git-scm.com/doc",description:"The official documentation portal for Git. Includes the reference manual, videos, and books.",type:"free",difficulty:"Beginner",badge:"Official",author:"Git Core Team"},{title:"Pro Git Book",url:"https://git-scm.com/book/en/v2",description:"The complete Pro Git book written by Scott Chacon and Ben Straub. Available online for free.",type:"free",difficulty:"Beginner",badge:"Must Read"}]},{id:"books",title:"Books",description:"Must-read titles that stand the test of time for Git mastery.",icon:"Library",resources:[{title:"Version Control with Git",url:"https://www.oreilly.com/library/view/version-control-with/9781492091189/",description:"A comprehensive guide to using Git, from basic commands to advanced branching, merging, and repositories.",type:"paid",difficulty:"Intermediate",author:"Jon Loeliger, Matthew McCullough",estimatedHours:25}]},{id:"video-courses",title:"Video Courses",description:"Structured video learning paths from beginner to expert level.",icon:"PlayCircle",resources:[{title:"Git & GitHub Bootcamp",url:"https://www.udemy.com/course/git-and-github-bootcamp/",description:"Colt Steele's ultimate guide to Git, branching, merging, rebasing, resolving conflicts, and collaboration on GitHub.",type:"paid",difficulty:"Beginner",badge:"Best Rated",author:"Colt Steele",estimatedHours:17},{title:"Git for Beginners — freeCodeCamp",url:"https://www.youtube.com/watch?v=RGOj5yH7evk",description:"A comprehensive Git tutorial covering everything from local workflow to remote repositories.",type:"free",difficulty:"Beginner",badge:"Free",author:"freeCodeCamp",estimatedHours:4}]},{id:"practice",title:"Practice Platforms",description:"Sharpen your Git with coding challenges and exercises.",icon:"Code2",resources:[{title:"Learn Git Branching",url:"https://learngitbranching.js.org/",description:"An interactive, visual game that walks you through commits, branches, rebases, and cherry-picks.",type:"free",difficulty:"Beginner",badge:"Community Pick"},{title:"Oh My Git!",url:"https://ohmygit.org/",description:"An open-source game about Git that teaches version control through real Git commands represented in visual cards.",type:"free",difficulty:"Beginner"}]},{id:"github",title:"GitHub Repositories",description:"Open-source projects and curated lists worth starring.",icon:"Github",resources:[{title:"Git Flight Rules",url:"https://github.com/k88hudson/git-flight-rules",description:"A guide for astronauts (now developers) about what to do when things go wrong with Git.",type:"free",difficulty:"Intermediate",badge:"Must Read"},{title:"First Contributions",url:"https://github.com/firstcontributions/first-contributions",description:"A simple repository designed to help beginners make their first open-source pull request.",type:"free",difficulty:"Beginner",badge:"Community Pick"}]},{id:"tools",title:"Developer Tools",description:"Essential tools for productive Git development.",icon:"Wrench",resources:[{title:"Gitkraken",url:"https://www.gitkraken.com/",description:"A powerful cross-platform Git GUI client with visual commits, branching, and conflicts resolver.",type:"freemium",difficulty:"Beginner"},{title:"GitHub Desktop",url:"https://desktop.github.com/",description:"Simple and clean GUI wrapper to manage repositories without typing commands in terminal.",type:"free",difficulty:"Beginner",badge:"Official"}]},{id:"community",title:"Community & Forums",description:"Active communities to ask questions and stay current.",icon:"Users",resources:[{title:"r/git",url:"https://www.reddit.com/r/git/",description:"Subreddit for discussions, announcements, and debugging questions related to Git.",type:"free",difficulty:"Beginner"}]}],learningPath:{totalWeeks:4,totalHours:35,level:"Beginner",description:"A 4-week fast-track program to master Git, starting from local file versioning to collaborative remote workflows and advanced operations.",weeks:[{week:1,title:"Git Basics & Local Workflow",description:"Initialize repositories, track modifications, write commits, and inspect change history.",topics:["git init and repository structures","Working Directory, Staging Area, and Commit History","git add, git commit, git status","Configuring user names and emails","git log and git diff"],estimatedHours:8,milestoneProject:"Create a local repository, write 5 commits, and inspect commits using custom log formatting"},{week:2,title:"Branching & Merging",description:"Create branches, merge features, and resolve merge conflicts.",topics:["Branching concepts & git branch","git checkout and git switch","Fast-Forward vs Three-Way Merges","Identifying and Resolving Merge Conflicts","git stash for temporary storage"],estimatedHours:9,milestoneProject:"Create a conflict between two branches and manually resolve it using git log --graph"},{week:3,title:"Remotes & Collaboration",description:"Sync local changes with Github, fetch updates, create pull requests, and clone existing projects.",topics:["git remote management","git push, git fetch, and git pull","Tracking branches and upstream links","Cloning repositories","Forking & creating Pull Requests on GitHub"],estimatedHours:9,milestoneProject:"Fork a public repository, clone it, create a branch, push it, and open a Pull Request"},{week:4,title:"Undoing Changes & Rewriting History",description:"Learn how to revert bad commits, reset files, interactive rebase, and checkout old references.",topics:["git checkout/restore on files","git reset: --soft, --mixed, --hard","git revert to create safety commits","Interactive Rebase (squashing, editing commits)","git cherry-pick"],estimatedHours:9,milestoneProject:"Use interactive rebase to sqush 3 temporary commits into a single clean commit"}]},skillTree:[{id:"git-basics",name:"Local Workflow",description:"Handling repositories, files, branches, and changes locally.",level:"category",children:[{id:"git-commit",name:"Staging & Commits",description:"Understanding the state machine of Git: working directory, staging index, and HEAD.",level:"topic",codeExample:`# Initialize a new repository
git init

# Stage a specific file
git add src/index.js

# Commit with a message
git commit -m "feat: add index file"

# Check status of the workspace
git status`},{id:"git-branching",name:"Branches & Merges",description:"Isolating code paths and integrating them back together.",level:"topic",codeExample:`# Create and switch to a new branch
git checkout -b feature/login

# Switch branch (modern command)
git switch main

# Merge feature branch back to main
git merge feature/login`}]},{id:"git-advanced",name:"History & Syncing",description:"Rewriting history, resolving conflicts, and syncing with remotes.",level:"category",children:[{id:"git-reset",name:"Reset & Revert",description:"Undoing changes safely using git reset and git revert.",level:"topic",codeExample:`# Undo the last commit, keep changes staged
git reset --soft HEAD~1

# Undo the last commit, discard all changes
git reset --hard HEAD~1

# Safely undo a commit by creating a new inverse commit
git revert a1b2c3d4`},{id:"git-rebase",name:"Rebasing & Cherry-Picking",description:"Reapplying commits on top of another base branch and picking individual commits.",level:"topic",codeExample:`# Reapply current branch commits on top of main
git rebase main

# Cherry-pick a specific commit from another branch
git cherry-pick d5e6f7g8

# Interactive rebase of the last 3 commits
git rebase -i HEAD~3`}]}],aiQA:[{keywords:["reset","revert","difference"],question:"What is the difference between git reset and git revert?",answer:"`git reset` rewires the branch reference (HEAD) back to a previous commit, rewriting history. It can discard changes (`--hard`) or keep them (`--soft`/`--mixed`). It should not be used on shared public branches. `git revert` creates a new commit that applies the exact inverse changes of a targeted commit. It is safe for public branches because it does not alter history."},{keywords:["rebase","merge","difference"],question:"What is the difference between merging and rebasing?",answer:'`git merge` combines two histories by creating a new "merge commit". It preserves the chronological order of commits and the branching structure. `git rebase` takes commits from a branch and reapplies them on top of another base branch, rewriting commit hashes. Rebasing produces a clean, linear git history but can be tricky when resolving conflicts on public branches.'},{keywords:["detached head","detached"],question:'What does "Detached HEAD" mean and how do you fix it?',answer:'A "Detached HEAD" occurs when you checkout a specific commit hash or remote tag instead of a local branch. HEAD is pointing directly to a commit instead of a branch reference. To save changes made in this state, create a new branch: `git checkout -b temp-branch`. If you just want to get back, switch to your main branch: `git switch main`.'}]}}};